const projects = $('Read All Project Data').all();
const stripeData = $('Stripe API Revenue (7 Days)').first().json;
const analyticsData = $('Plausible Analytics (7 Days)').first().json;

// Summarize project data
const liveProducts = projects.filter(p => p.json.status === 'LIVE');
const thisWeekLaunched = projects.filter(p => {
  const launchedAt = new Date(p.json.launched_at);
  const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
  return launchedAt > weekAgo;
});

// Revenue summary
const charges = (stripeData.data || []);
const totalRevenue = charges.reduce((sum, c) => sum + (c.amount || 0), 0) / 100;
const successfulCharges = charges.filter(c => c.status === 'succeeded');

return [{
  json: {
    total_products: projects.length,
    live_products: liveProducts.length,
    launched_this_week: thisWeekLaunched.length,
    weekly_revenue_usd: totalRevenue,
    successful_charges: successfulCharges.length,
    analytics: analyticsData.results || {},
    status_breakdown: {
      PENDING_APPROVAL: projects.filter(p => p.json.status === 'PENDING_APPROVAL').length,
      APPROVED: projects.filter(p => p.json.status === 'APPROVED').length,
      BUILDING: projects.filter(p => p.json.status === 'BUILDING').length,
      BUILD_COMPLETE: projects.filter(p => p.json.status === 'BUILD_COMPLETE').length,
      QA_PASSED: projects.filter(p => p.json.status === 'QA_PASSED').length,
      LIVE: liveProducts.length,
      BUILD_FAILED: projects.filter(p => p.json.status === 'BUILD_FAILED').length,
      QA_FAILED: projects.filter(p => p.json.status === 'QA_FAILED').length,
      SUNSET: projects.filter(p => p.json.status === 'SUNSET').length
    },
    product_details: liveProducts.map(p => ({
      name: p.json.product_name,
      category: p.json.category,
      launched_at: p.json.launched_at,
      url: p.json.live_url
    }))
  }
}];

const retroResponse = $input.first().json;
const aggregated = $('Aggregate All Data').first().json;

let retroResult;
try {
  const textBlock = retroResponse.content.find(b => b.type === 'text');
  const match = textBlock.text.match(/\{[\s\S]*\}/);
  retroResult = JSON.parse(match[0]);
} catch (e) {
  retroResult = { summary: 'Failed to parse retrospective', learnings: [], recommendations: [] };
}

// Prepare learnings for Config tab
const learningRows = (retroResult.learnings || []).map((l, i) => ({
  type: 'learning',
  content: l.insight,
  action: l.action,
  priority: l.priority,
  source: 'retrospective',
  date: new Date().toISOString().split('T')[0],
  week: 'W' + Math.ceil((new Date().getDate()) / 7)
}));

return [{
  json: {
    retro_result: retroResult,
    aggregated_data: aggregated,
    learning_rows: learningRows
  }
}];
